const inputData = $input.first().json;
const apiKey = $env.PYTHON_SERVICE_API_KEY;

return this.helpers.request({
  method: 'POST',
  uri: 'http://python-service:8001/search',
  headers: {
    'Content-Type': 'application/json',
    'X-API-Key': apiKey
  },
  body: {
    query: inputData.query,
    top_k: 5,
    department: inputData.department
  },
  json: true
}).then(response => [{ json: response }]);

parameters.functionCode:
const queryData = $('Preprocess Query').first().json;
const searchResults = $input.first().json.results;

let context = '';
let sources = [];

if (searchResults && searchResults.length > 0) {
  context = searchResults.map((result, index) => {
    sources.push({
      title: result.title,
      source: result.source,
      department: result.department,
      score: result.score
    });
    return `[${index + 1}] ${result.title}\nSource: ${result.source}\nDepartment: ${result.department}\nContent: ${result.content}\n`;
  }).join('\n---\n\n');
} else {
  context = 'No relevant documents found in the knowledge base.';
}

const prompt = `You are a helpful enterprise assistant with access to company documents. Answer the user's question based on the provided context.\n\n## Context from Company Documents:\n${context}\n\n## User Question:\n${queryData.query}\n\n## Instructions:\n- Answer based primarily on the provided context\n- If the context does not contain enough information, clearly state this\n- Provide specific references to source documents when possible\n- Be concise but comprehensive\n- Use a professional but friendly tone\n\n## Answer:`;

return {
  prompt: prompt,
  query: queryData.query,
  sources: sources,
  requestId: queryData.requestId,
  userId: queryData.userId,
  sessionId: queryData.sessionId,
  department: queryData.department
};

