const promptData = $('Prepare Claude Prompt').first().json;
const claudeResponse = $input.first().json;

let answer = '';
if (claudeResponse.content && claudeResponse.content.length > 0) {
  answer = claudeResponse.content[0].text;
} else {
  answer = 'I apologize, but I was unable to generate a response. Please try again.';
}

return {
  answer: answer,
  query: promptData.query,
  sources: promptData.sources,
  metadata: {
    requestId: promptData.requestId,
    userId: promptData.userId,
    sessionId: promptData.sessionId,
    department: promptData.department,
    timestamp: new Date().toISOString(),
    model: 'claude-sonnet-4-20250514',
    sourceCount: promptData.sources.length
  }
};

